content_sections.code_example:
# Basic for loop
for i in range(5):
    print(f'House {i}')

# range with start and stop
for i in range(1, 6):
    print(i)    # prints 1, 2, 3, 4, 5

# range with step
for i in range(0, 10, 2):
    print(i)    # prints 0, 2, 4, 6, 8

# Looping over a string
for char in 'Python':
    print(char)  # prints each letter

